const item = $input.first().json;
const raw = (item.characterName != null && item.characterName !== '') ? String(item.characterName) : 'Hana';
const names = raw.split(',').map(s => s.trim()).filter(Boolean);
if (names.length === 0) names.push('Hana');
const base = 'https://wddatxgqhdiosuhcztex.supabase.co/rest/v1/avatars';
const inFilter = 'in.(' + names.map(n => '"' + n.replace(/"/g, '') + '"').join(',') + ')';
const url = base + '?select=character_name,character_prompt,gender&character_name=' + encodeURIComponent(inFilter);
return [{ json: { chatInput: item.chatInput, characterName: item.characterName, avatarFetchUrl: url } }];

const items = $input.all();
const rows = [];
items.forEach(i => {
  const j = i.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && typeof j === 'object' && (j.character_name != null || j.body != null)) {
    if (Array.isArray(j.body)) rows.push(...j.body);
    else rows.push(j);
  }
});
const byName = {};
let avatarGender = 'girl';
rows.forEach(r => {
  const n = r.character_name;
  const p = r.character_prompt;
  const g = r.gender;
  if (n) byName[n] = (p != null && p !== '') ? p : '(personnage principal, apparence à respecter selon le contexte)';
  if (g && (g === 'boy' || g === 'girl')) avatarGender = g;
});
const characterBible = Object.entries(byName)
  .map(([name, prompt]) => name + ': ' + prompt)
  .join('\n');
return [{ json: { characterBible: characterBible || 'No characters found. Use default style.', avatarGender } }];

const merge = $('Merge chatInput + character bible').first().json;
const storyInput = (merge.chatInput || '').trim();
const characterBible = merge.characterBible || '';
const fullPrompt = `Tu es un auteur narratif manga pour enfants (6-10 ans). Tu crées une histoire courte ADAPTÉE aux personnages dont la bible visuelle est donnée ci-dessous.

BIBLE VISUELLE DES PERSONNAGES (source : base de données, à respecter STRICTEMENT pour les panels et scene_summary) :
${characterBible}

ENTRÉE UTILISATEUR (thème, synopsis, ou texte d'histoire - peut être vide) :
${storyInput || '(aucun - invente une aventure courte qui correspond aux personnages)'}

TÂCHE :
- Si l'utilisateur a fourni un thème ou synopsis : invente une histoire de 5 pages qui le respecte et met en scène les personnages de la bible.
- Si l'utilisateur a fourni un texte d'histoire complet : découpe-le en 5 pages narratives.
- Si l'utilisateur n'a rien fourni : invente une aventure de 5 pages adaptée au design et à l'univers des personnages.
- Les personnages dans chaque scene_summary et dans chaque panel doivent correspondre EXACTEMENT à la bible visuelle. Ne pas modifier leur apparence.
- Produire : paragraph_text, scene_summary, panels (descriptions visuelles pures, pas de bulles ni texte), 2 choix par page sauf la dernière. Générer aussi story_starts (2-3 accroches) et universe (métadonnées dérivées de l'histoire).

FORMAT DE SORTIE : JSON strict uniquement. Pas de markdown. Schéma : universe (id, name, description, image_url, color, emoji, gender, display_order), story_starts (id, title, text, paragraph_text, scene_summary), pages (universe_id, page_number, paragraph_text, scene_summary, panels[], choices[]).`;
return [{ json: { fullPrompt, characterBible } }];

const raw = $input.first().json.output[0].content[0].text;

let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/```json/g, '').replace(/```/g, '').trim();
}

const parsed = JSON.parse(cleaned);
const pages = parsed.pages || [parsed.page];
const universe = parsed.universe || null;

const BUCKET = 'BD-Pages';
const SUPABASE_URL = 'https://wddatxgqhdiosuhcztex.supabase.co';
const now = new Date().toISOString();

let characterBible = '';
let avatarGender = 'girl';
try { const m = $('Merge chatInput + character bible').first().json; characterBible = m.characterBible || ''; avatarGender = m.avatarGender || 'girl'; } catch (e) {}
const CHARACTER_LOCK = characterBible
  ? '\nCharacter reference (STRICT - MUST remain identical in every image):\n\n' + characterBible + '\n\nDO NOT change character design.\n'
  : '\nMain character: 8-year-old girl, short black bob, red ribbon left, emerald eyes, blue tunic, brown boots. DO NOT change design.\n';

return pages.map(page => {
  const universeId = page.universe_id;
  const pageNumber = page.page_number;
  const fileName = `${universeId}-page-${pageNumber}.png`;
  const storagePath = `${universeId}/${fileName}`;

  return {
    json: {
      universe,
      universeId,
      pageNumber,
      paragraphText: page.paragraph_text,
      sceneSummary: page.scene_summary,
      panels: page.panels,
      choices: page.choices || [],
      storyStarts: parsed.story_starts || [],
      avatarGender,
      bucket: BUCKET,
      fileName,
      storagePath,
      supabaseUrl: SUPABASE_URL,
      createdAt: now,
      geminiPrompt: `Create a full children manga page illustration.\n\nSTYLE:\nSoft pastel Japanese children manga style.\nNo text. No speech bubbles. No typography.\n\n${CHARACTER_LOCK}\n\nSCENE:\n${page.scene_summary}\n\nPANELS:\n${JSON.stringify(page.panels, null, 2)}\n\nMaintain strict character consistency.`
    }
  };
});

const item = $input.first().json;
const u = item.universe;
if (!u) return [];
const gender = item.avatarGender || u.gender || 'girl';
return [{
  json: {
    id: u.id,
    name: u.name,
    description: u.description,
    image_url: u.image_url || '',
    color: u.color,
    emoji: u.emoji,
    gender: gender,
    display_order: u.display_order
  }
}];

const parseItem = $('Parse story JSON').first().json;
const starts = parseItem.storyStarts || [];
const universeId = parseItem.universeId;

if (!starts.length) return [];

return starts.map(s => ({
  json: {
    id: s.id,
    universe_id: universeId,
    title: s.title,
    text: s.text
  }
}));

const items = $input.all();
return items.map(item => ({
  json: {
    universe_id: item.json.universeId,
    page_number: item.json.pageNumber,
    text: item.json.paragraphText,
    image_url: `${item.json.supabaseUrl}/storage/v1/object/public/${item.json.bucket}/${item.json.storagePath}`,
    created_at: item.json.createdAt
  }
}));

const items = $input.all();
const results = [];
for (const item of items) {
  const choices = item.json.choices || [];
  choices.forEach((choice, index) => {
    results.push({
      json: {
        id: choice.id,
        universe_id: item.json.universeId,
        page_number: item.json.pageNumber,
        choice_order: index + 1,
        text: choice.text,
        created_at: item.json.createdAt
      }
    });
  });
}
return results;
